function solve(n, edges, k) {
  // Sort edges by time in ascending order
  edges.sort((a, b) => a[2] - b[2]);

  // Initialize parent array for Union-Find
  const parent = Array(n).fill().map((_, i) => i);

  function find(x) {
    if (parent[x] !== x) {
      parent[x] = find(parent[x]);
    }
    return parent[x];
  }

  function union(x, y) {
    const rootX = find(x);
    const rootY = find(y);
    if (rootX !== rootY) {
      parent[rootY] = rootX;
    }
  }

  function countComponents() {
    const roots = new Set();
    for (let i = 0; i < n; i++) {
      roots.add(find(i));
    }
    return roots.size;
  }

  // Binary search for the minimum time t
  let left = 0;
  let right = edges.length > 0 ? edges[edges.length - 1][2] : 0;
  let result = right;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    // Reset parent array for each binary search step
    parent.forEach((_, i) => parent[i] = i);
    // Remove all edges with time <= mid
    for (const [u, v, time] of edges) {
      if (time <= mid) {
        union(u, v);
      }
    }

    const components = countComponents();
    if (components >= k) {
      result = mid;
      right = mid - 1;
    } else {
      left = mid + 1;
    }
  }

  return result;
}
